import sys
sys.setrecursionlimit(50)
from cachetools import LRUCache, cached
from cachetools.keys import hashkey

class RecursiveEquals:
    def __init__(self, use_cache):
        self._use_cache = use_cache
    def __hash__(self):
        return hash(self._use_cache)
    def __eq__(self, other):
        if self._use_cache:
            cached(self)
        return self._use_cache == other._use_cache

cache = LRUCache(maxsize=128)
wrapper = cached(cache, key=hashkey)(lambda n: n)
wrapper(RecursiveEquals(False))
wrapper(RecursiveEquals(True))
try:
    result = wrapper(RecursiveEquals(True))
    print('SUCCESS:', result)
except RecursionError as e:
    print('RECURSION ERROR:', e)
except Exception as e:
    print(f'OTHER ERROR: {type(e).__name__}: {e}')
